		testHandlers.GetCoursesHandler(w, req)

		res := w.Result()
		if res.StatusCode != http.StatusOK {
			t.Fatalf("expected 200, got %d", res.StatusCode)
		}
		var body GetCoursesResult
		if err := json.NewDecoder(res.Body).Decode(&body); err != nil {
			t.Fatalf("failed to decode body: %v", err)
		}
		if len(body.Courses) == 0 {
			t.Error("expected non-empty courses")
		}
	})

	t.Run("キーワードでタイトルを検索できる", func(t *testing.T) {
		params := url.Values{}
		params.Set("keyword", "タイトル一致テスト")
		req := httptest.NewRequest("GET", "/v1/courses?"+params.Encode(), nil)
		w := httptest.NewRecorder()

		testHandlers.GetCoursesHandler(w, req)

		res := w.Result()
		if res.StatusCode != http.StatusOK {
			t.Fatalf("expected 200, got %d", res.StatusCode)
		}
		var body GetCoursesResult
		if err := json.NewDecoder(res.Body).Decode(&body); err != nil {
			t.Fatalf("failed to decode body: %v", err)
		}
		if len(body.Courses) != 1 {
			t.Fatalf("expected 1 course, got %d", len(body.Courses))
		}
		if body.Courses[0].Title != "タイトル一致テスト専用コース" {
			t.Errorf("unexpected title: %s", body.Courses[0].Title)
		}
	})

	t.Run("キーワードで説明を検索できる", func(t *testing.T) {
		params := url.Values{}
		params.Set("keyword", "説明文一致テスト")
		req := httptest.NewRequest("GET", "/v1/courses?"+params.Encode(), nil)
		w := httptest.NewRecorder()

		testHandlers.GetCoursesHandler(w, req)

		res := w.Result()
		if res.StatusCode != http.StatusOK {
			t.Fatalf("expected 200, got %d", res.StatusCode)
		}
		var body GetCoursesResult
		if err := json.NewDecoder(res.Body).Decode(&body); err != nil {
			t.Fatalf("failed to decode body: %v", err)
		}
		if len(body.Courses) != 1 {
			t.Fatalf("expected 1 course, got %d", len(body.Courses))
		}
		if body.Courses[0].Title != "通常コースB" {
			t.Errorf("unexpected title: %s", body.Courses[0].Title)
		}
	})

	t.Run("カーソルでページネーションができる", func(t *testing.T) {
		params := url.Values{}
		params.Set("keyword", "ページネーションテスト")
		req := httptest.NewRequest("GET", "/v1/courses?"+params.Encode(), nil)
		w := httptest.NewRecorder()

		testHandlers.GetCoursesHandler(w, req)

		res := w.Result()
		if res.StatusCode != http.StatusOK {
			t.Fatalf("expected 200, got %d", res.StatusCode)
		}
		var body GetCoursesResult
		if err := json.NewDecoder(res.Body).Decode(&body); err != nil {
			t.Fatalf("failed to decode body: %v", err)
		}
		if body.Cursor == nil {
			t.Error("expected non-nil cursor for 201 courses")
		}
	})

	t.Run("次のページがない場合カーソルが null", func(t *testing.T) {
		params := url.Values{}
		params.Set("keyword", "タイトル一致テスト")
		req := httptest.NewRequest("GET", "/v1/courses?"+params.Encode(), nil)
		w := httptest.NewRecorder()

		testHandlers.GetCoursesHandler(w, req)

		res := w.Result()
		if res.StatusCode != http.StatusOK {
			t.Fatalf("expected 200, got %d", res.StatusCode)
		}
		var body GetCoursesResult
		if err := json.NewDecoder(res.Body).Decode(&body); err != nil {
			t.Fatalf("failed to decode body: %v", err)
		}
		if body.Cursor != nil {
			t.Errorf("expected nil cursor, got %s", *body.Cursor)
		}
	})
}

