	"os"
	"testing"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgxpool"
)

const (
	testCategoryID = "10000000-0000-0000-0000-000000000000"
	testAuthorID   = "20000000-0000-0000-0000-000000000000"
	titleCourseID  = "30000000-0000-0000-0000-000000000001"
	descCourseID   = "30000000-0000-0000-0000-000000000002"
)

var testHandlers *Handlers

func databaseURL() string {
	if dsn := os.Getenv("DATABASE_URL"); dsn != "" {
		return dsn
	}
	return "postgresql://postgres:password@localhost:5432/postgres"
}

func TestMain(m *testing.M) {
	ctx := context.Background()
	pool, err := pgxpool.New(ctx, databaseURL())
	if err != nil {
		panic(fmt.Sprintf("failed to connect to db: %v", err))
	}

	if err := setupTestData(ctx, pool); err != nil {
		pool.Close()
		panic(fmt.Sprintf("failed to setup test data: %v", err))
	}

	svc := NewSqrcCourseQueryService(db.New(pool))
	testHandlers = NewCoursesHandlers(svc)

	code := m.Run()

	cleanupTestData(ctx, pool)
	pool.Close()
	os.Exit(code)
}

